// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const forecastItems = useMemo(() => props.forecast.slice(0, 5), [props.forecast]);
  const weatherIcon = useMemo(() => {
    const condition = props.condition.toLowerCase();
    if (condition.includes('rain')) return 'cloud-rain';
    if (condition.includes('cloud')) return 'cloud';
    if (condition.includes('snow')) return 'cloud-snow';
    if (condition.includes('storm') || condition.includes('thunder')) return 'cloud-lightning';
    if (condition.includes('fog') || condition.includes('mist')) return 'cloud-fog';
    return 'sun';
  }, [props.condition]);

  const getForecastDisplay = useCallback((icon?: string, day?: string) => {
    const value = (icon ?? '').trim();
    const lowered = value.toLowerCase();

    const emojiMap: Record<string, string> = {
      sunny: '☀️',
      sun: '☀️',
      clear: '☀️',
      cloudy: '☁️',
      cloud: '☁️',
      overcast: '☁️',
      rainy: '🌧️',
      rain: '🌧️',
      drizzle: '🌦️',
      storm: '⛈️',
      thunder: '⛈️',
      lightning: '⛈️',
      snowy: '❄️',
      snow: '❄️',
      fog: '🌫️',
      mist: '🌫️',
      wind: '💨',
    };

    if (emojiMap[lowered]) return emojiMap[lowered];
    if (lowered.includes('rain')) return '🌧️';
    if (lowered.includes('cloud')) return '☁️';
    if (lowered.includes('snow')) return '❄️';
    if (lowered.includes('storm') || lowered.includes('thunder') || lowered.includes('lightning')) return '⛈️';
    if (lowered.includes('fog') || lowered.includes('mist')) return '🌫️';
    if (lowered.includes('sun') || lowered.includes('clear')) return '☀️';

    return day ? day.slice(0, 1).toUpperCase() : '•';
  }, []);

  return { forecastItems, weatherIcon, getForecastDisplay };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Card padding={24} shadow="md" radius="lg">
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.city}</Text>
            <Row align="center" gap={16} wrap>
              <Heading level={1}>{props.temperature}&deg;{props.unit}</Heading>
              <Stack direction="horizontal" align="center" gap={8}>
                <Icon name={state.weatherIcon} size={28} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="bodyLarge">{props.condition}</Text>
              </Stack>
            </Row>
          </Stack>

          <Row gap={16} wrap>
            <Card padding={16} shadow="none" border radius="md">
              <Stack gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text variant="bodyLarge" weight="semibold">{props.humidity}%</Text>
              </Stack>
            </Card>
            <Card padding={16} shadow="none" border radius="md">
              <Stack gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                <Text variant="bodyLarge" weight="semibold">{props.windSpeed}</Text>
              </Stack>
            </Card>
          </Row>

          <Divider />

          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-Day Forecast</Text>
            <Row gap={12} wrap>
              {state.forecastItems.map((item, index) => (
                <Card key={`${item.day ?? 'day'}-${index}`} padding={12} shadow="none" border radius="md">
                  <Stack gap={8} align="center">
                    <Text variant="caption" weight="medium">{item.day ?? `Day ${index + 1}`}</Text>
                    <Text variant="bodyLarge" is="span" aria-label={item.icon ? `Forecast ${item.day ?? `day ${index + 1}`}: ${item.icon}` : `Forecast ${item.day ?? `day ${index + 1}`}`}>
                      {state.getForecastDisplay(item.icon, item.day)}
                    </Text>
                    <Text variant="bodySmall" align="center">
                      {typeof item.high === 'number' ? `${item.high}°${props.unit}` : `--${props.unit}`} / {typeof item.low === 'number' ? `${item.low}°${props.unit}` : `--${props.unit}` }
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit: (payload: ActionSubmitPayload) => void; // Called with all collected answers as a structured object
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  // Actions — fire-and-forget to agent
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const emailIsValid = useCallback((value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value), []);
  const nameError = nameTouched && !name.trim() ? 'Name is required' : '';
  const emailError = emailTouched && !email.trim() ? 'Email is required' : emailTouched && email.trim() && !emailIsValid(email) ? 'Enter a valid email address' : '';
  const step1Valid = !!name.trim() && !!email.trim() && emailIsValid(email);
  const step2Valid = satisfaction >= 1 && satisfaction <= 5;
  const step3Valid = true;
  const step4Valid = comments.length <= 500;
  const canGoNext = step === 1 ? step1Valid : step === 2 ? step2Valid : step === 3 ? step3Valid : step4Valid;
  const progressValue = (step / 4) * 100;
  const progressLabel = `Step ${step} of 4`;
  const handleNext = useCallback(() => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    if (step < 4) {
      setStep((current) => current + 1);
    }
  }, [step, step1Valid, step2Valid]);
  const handleBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);
  const toggleFeature = useCallback((feature: string) => {
    setFeatures((current) =>
      current.includes(feature) ? current.filter((item) => item !== feature) : [...current, feature]
    );
  }, []);
  const handleSubmit = useCallback(() => {
    const payload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    };
    props.onSubmit(payload);
    setSubmitted(true);
    setStep(5);
  }, [props, name, email, satisfaction, features, comments]);
  return {
    // submit,
    step,
    setStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    comments,
    setComments,
    nameTouched,
    setNameTouched,
    emailTouched,
    setEmailTouched,
    submitted,
    setSubmitted,
    emailIsValid,
    nameError,
    emailError,
    step1Valid,
    step2Valid,
    step3Valid,
    step4Valid,
    canGoNext,
    progressValue,
    progressLabel,
    handleNext,
    handleBack,
    toggleFeature,
    handleSubmit,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Box>
          <Stack gap={8}>
            <Row align="center" justify="between">
              <Heading level={2}>Multi-step survey</Heading>
              <Text variant="label">{state.progressLabel}</Text>
            </Row>
            <Progress value={state.progressValue} max={100} showLabel />
          </Stack>
        </Box>

        <Card shadow="sm" padding={24} radius="lg">
          <Stack gap={24}>
            {state.step === 1 && (
              <Stack gap={16}>
                <Heading level={4}>About you</Heading>
                <Input
                  label="Name"
                  value={state.name}
                  onChange={(value) => { state.setName(value); if (!state.nameTouched) state.setNameTouched(true); }}
                  required
                  error={state.nameError}
                  onBlur={() => state.setNameTouched(true)}
                />
                <Input
                  label="Email"
                  type="email"
                  value={state.email}
                  onChange={(value) => { state.setEmail(value); if (!state.emailTouched) state.setEmailTouched(true); }}
                  required
                  error={state.emailError}
                  onBlur={() => state.setEmailTouched(true)}
                />
              </Stack>
            )}

            {state.step === 2 && (
              <Stack gap={16}>
                <Heading level={4}>Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={String(state.satisfaction)}
                  onChange={(value) => state.setSatisfaction(Number(value))}
                  options={props.satisfactionLabels.map((label, index) => ({ value: String(index + 1), label }))}
                />
              </Stack>
            )}

            {state.step === 3 && (
              <Stack gap={16}>
                <Heading level={4}>Feature interests</Heading>
                <Stack gap={12}>
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.features.includes(feature)}
                      onChange={() => state.toggleFeature(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {state.step === 4 && (
              <Stack gap={16}>
                <Heading level={4}>Comments</Heading>
                <TextArea
                  label="Open-ended comments"
                  value={state.comments}
                  onChange={(value) => { if (value.length <= 500) state.setComments(value); }}
                  maxLength={500}
                  showCount
                  rows={6}
                  helperText="Optional feedback, up to 500 characters"
                />
              </Stack>
            )}

            {state.step === 5 && (
              <Stack gap={16}>
                <Heading level={4}>Review your answers</Heading>
                <Card shadow="none" border radius="md" padding={16}>
                  <Stack gap={12}>
                    <Text><Text is="span" weight="semibold">Name:</Text> {state.name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {state.email || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Satisfaction:</Text> {state.satisfaction ? props.satisfactionLabels[state.satisfaction - 1] ?? String(state.satisfaction) : '—'}</Text>
                    <Text><Text is="span" weight="semibold">Features:</Text> {state.features.length ? state.features.join(', ') : 'None selected'}</Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {state.comments || '—'}</Text>
                  </Stack>
                </Card>
                {state.submitted ? (
                  <Alert variant="success" title="Submitted">Thank you for completing the survey.</Alert>
                ) : null}
              </Stack>
            )}
              </Stack>
            )}

            <Divider />

            <Row justify="between" align="center">
              <Button variant="outline" onClick={state.handleBack} disabled={state.step === 1}>Back</Button>
              <Spacer size="flex" />
              {state.step < 4 ? (
                <Button variant="primary" onClick={state.handleNext} disabled={!state.canGoNext}>Next</Button>
              ) : state.step === 4 ? (
                <Button variant="primary" onClick={state.handleNext} disabled={!state.canGoNext}>Review</Button>
              ) : (
                <Button variant="primary" onClick={state.handleSubmit}>Submit</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  const initialTasks = props.tasks.map((task, index) => ({
    id: task.id || `task-${index + 1}`,
    title: task.title || 'Untitled task',
    priority: task.priority || 'medium',
    assignee: task.assignee || '',
    column: task.column || 'todo',
    dueDate: task.dueDate,
  }));

  const [tasks, setTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>(initialTasks);
  const [draftTitleByColumn, setDraftTitleByColumn] = useState<Record<string, string>>({});
  const [draftPriorityByColumn, setDraftPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [moveTargetByTask, setMoveTargetByTask] = useState<Record<string, string>>({});
  const [pendingRemoteAction, setPendingRemoteAction] = useState<StreamTaskChanged | undefined>(undefined);

  const defaultColumns = ['todo', 'in-progress', 'done'];
  const normalizedColumns = props.columns.map((column, index) => ({
    id: column.id || defaultColumns[index] || `column-${index + 1}`,
    name: column.name || ['To Do', 'In Progress', 'Done'][index] || `Column ${index + 1}`,
  }));

  const updateTaskAction = useAction('taskUpdate');

  const syncTaskUpdate = useCallback((payload: ActionTaskUpdatePayload) => {
    if (typeof updateTaskAction === 'function') {
      updateTaskAction(payload);
    }
  }, [updateTaskAction]);

  const applyRemoteTask = useCallback((incoming: StreamTaskChanged['task']) => {
    if (!incoming) {
      return;
    }
    const taskId = incoming.id || `stream-${Date.now()}`;
    setTasks((current) => {
      const existingIndex = current.findIndex((task) => task.id === taskId);
      const nextTask = {
        id: taskId,
        title: incoming.title || 'Untitled task',
        priority: incoming.priority || 'medium',
        assignee: incoming.assignee || '',
        column: incoming.column || 'todo',
        dueDate: incoming.dueDate,
      };
      if (existingIndex === -1) {
        return [nextTask, ...current];
      }
      const copy = current.slice();
      copy[existingIndex] = { ...copy[existingIndex], ...nextTask };
      return copy;
    });
  }, []);

  const applyRemoteChange = useCallback((detail: StreamTaskChanged | undefined) => {
    if (!detail) {
      return;
    }
    setPendingRemoteAction(detail);
    if (detail.action === 'delete' && detail.task?.id) {
      const taskId = detail.task.id;
      setTasks((current) => current.filter((task) => task.id !== taskId));
      return;
    }
    applyRemoteTask(detail.task);
  }, [applyRemoteTask]);

  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      applyRemoteChange(customEvent.detail);
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, [applyRemoteChange]);

  const handleCreateTask = useCallback((columnId: string) => {
    const title = (draftTitleByColumn[columnId] || '').trim();
    if (!title) {
      return;
    }
    const id = `task-${Date.now()}`;
    const newTask = { id, title, priority: draftPriorityByColumn[columnId] || 'medium', assignee: '', column: columnId, dueDate: undefined };
    setTasks((current) => [newTask, ...current]);
    syncTaskUpdate({ action: 'create', taskId: id, data: { column: columnId } });
    setDraftTitleByColumn((current) => ({ ...current, [columnId]: '' }));
    setDraftPriorityByColumn((current) => ({ ...current, [columnId]: 'medium' }));
    setAddingColumnId(null);
    setMoveTargetByTask((current) => ({ ...current, [id]: columnId }));
  }, [draftPriorityByColumn, draftTitleByColumn, syncTaskUpdate]);

  const handleMoveTask = useCallback((taskId: string, nextColumn: string) => {
    setTasks((current) => current.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
    setMoveTargetByTask((current) => ({ ...current, [taskId]: nextColumn }));
    syncTaskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
  }, [syncTaskUpdate]);

  const handleEditTask = useCallback((taskId: string, nextTitle: string) => {
    const trimmed = nextTitle.trim();
    if (!trimmed) {
      return;
    }
    const task = tasks.find((item) => item.id === taskId);
    setTasks((current) => current.map((item) => (item.id === taskId ? { ...item, title: trimmed } : item)));
    setEditingTaskId(null);
    setEditingTitle('');
    syncTaskUpdate({ action: 'edit', taskId, data: { column: task?.column || 'todo' } });
  }, [syncTaskUpdate, tasks]);

  const beginEditTask = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const completedCount = tasks.filter((task) => task.column === 'done').length;
  const totalCount = tasks.length;

  const groupedTasks = normalizedColumns.map((column) => ({
    ...column,
    tasks: tasks.filter((task) => task.column === column.id),
  }));

  const clientState = {
    tasks,
    columns: normalizedColumns,
    totalCount,
    completedCount,
    groupedTasks,
    editingTaskId,
    editingTitle,
    draftTitleByColumn,
    draftPriorityByColumn,
    addingColumnId,
    moveTargetByTask,
    setDraftTitleByColumn,
    setDraftPriorityByColumn,
    setAddingColumnId,
    setEditingTaskId,
    setEditingTitle,
    syncTaskUpdate,
    handleCreateTask,
    handleMoveTask,
    handleEditTask,
    beginEditTask,
    applyRemoteTask,
    pendingRemoteAction,
    setTasks,
    setPendingRemoteAction,
  };

  return { taskUpdate: syncTaskUpdate, taskChanged: pendingRemoteAction, ...clientState };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const priorityVariant = (priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  };

export default function Component(props: Props) {
  const state = useComponent(props);

  const priorityVariant = (priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  };

  const priorityOptions = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
  ];

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Card padding={20} shadow="sm" radius="lg">
          <Stack gap={12}>
            <Row align="center" justify="between">
              <Heading level={2}>Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {state.totalCount} tasks • {state.completedCount} completed
              </Text>
            </Row>
            <Progress value={state.totalCount === 0 ? 0 : (state.completedCount / state.totalCount) * 100} max={100} size="md" showLabel />
            {state.pendingRemoteAction?.action ? (
              <Alert variant="info" title="Live update received">
                Another team member updated a task on the board.
              </Alert>
            ) : null}
          </Stack>
        </Card>

        <Row gap={16} align="stretch" wrap>
          {state.columns.map((column) => {
            const columnTasks = state.groupedTasks.find((group) => group.id === column.id)?.tasks || [];
            return (
              <Card key={column.id} padding={16} shadow="sm" radius="lg">
                <Stack gap={16}>
                  <Row align="center" justify="between">
                    <Heading level={3}>{column.name}</Heading>
                    <Badge variant="primary" size="sm">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap={12}>
                    {columnTasks.map((task) => (
                      <Card key={task.id} padding={12} shadow="none" radius="md" border>
                        <Stack gap={10}>
                          <Row align="center" justify="between">
                            <Badge variant={priorityVariant(task.priority)} size="sm">{task.priority}</Badge>
                            <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                          </Row>

                          {state.editingTaskId === task.id ? (
                            <Stack gap={8}>
                              <Input
                                label={`Edit title for ${task.title}`}
                                value={state.editingTitle}
                                onChange={state.setEditingTitle}
                                size="sm"
                                onBlur={() => state.handleEditTask(task.id, state.editingTitle)}
                                onKeyDown={(event) => {
                                  if (event.key === 'Enter') {
                                    state.handleEditTask(task.id, state.editingTitle);
                                  }
                                  if (event.key === 'Escape') {
                                    state.setEditingTaskId(null);
                                    state.setEditingTitle('');
                                  }
                                }}
