// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [query, setQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);

  const categoryColors = useMemo(() => ({
    'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
    'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'post-transition-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
    metalloid: 'var(--ggui-color-info-100, #cffafe)',
    nonmetal: 'var(--ggui-color-success-100, #dcfce7)',
    halogen: 'var(--ggui-color-warning-200, #fde68a)',
    'noble-gas': 'var(--ggui-color-info-50, #ecfeff)',
    lanthanide: 'var(--ggui-color-primary-200, #bae6fd)',
    actinide: 'var(--ggui-color-error-50, #fef2f2)',
    unknown: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  }), []);

  const normalizedQuery = query.trim().toLowerCase();

  const matchesQuery = useCallback((element: Props['elements'][number]) => {
    if (!normalizedQuery) return true;
    return `${element.name ?? ''} ${element.symbol ?? ''}`.toLowerCase().includes(normalizedQuery);
  }, [normalizedQuery]);

  const visibleElements = useMemo(() => props.elements.filter(matchesQuery), [props.elements, matchesQuery]);

  const categoryColor = useCallback((category?: string) => {
    return categoryColors[(category ?? 'unknown').toLowerCase() as keyof typeof categoryColors] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  }, [categoryColors]);

  const legendItems = useMemo(() => {
    const categories = Array.from(new Set(props.elements.map((element) => (element.category ?? 'unknown').toLowerCase())));
    return categories.sort().map((category) => ({ category, color: categoryColor(category) }));
  }, [props.elements, categoryColor]);

  const gridCells = useMemo(() => {
    const cells: Array<{ row: number; col: number; element: Props['elements'][number] | null }> = [];
    for (let row = 1; row <= 10; row += 1) {
      for (let col = 1; col <= 18; col += 1) {
        cells.push({ row, col, element: null });
      }
    }

    props.elements.forEach((element) => {
      const row = element.row ?? 1;
      const col = element.col ?? 1;
      const index = (row - 1) * 18 + (col - 1);
      if (index >= 0 && index < cells.length) {
        cells[index] = { row, col, element };
      }
    });

    return cells;
  }, [props.elements]);

  return {
    query,
    setQuery,
    selectedElement,
    setSelectedElement,
    visibleElements,
    gridCells,
    categoryColor,
    legendItems,
    matchesQuery,
  };
}
}

