// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  const addToCart = useCallback((payload: ActionAddToCartPayload) => {
    void payload;
  }, []);

  const product = props.product ?? {};
  const productId = product.id ?? '';
  const productName = product.name ?? 'Product';
  const price = typeof product.price === 'number' ? product.price : 0;
  const currency = product.currency ?? 'USD';
  const rating = Math.max(0, Math.min(5, Math.round(product.rating ?? 0)));
  const reviewCount = product.reviewCount ?? 0;
  const stock = Math.max(0, Math.floor(product.stock ?? 0));
  const description = product.description ?? '';
  const specifications = Array.isArray(product.specifications) ? product.specifications : [];
  const reviews = Array.isArray(product.reviews) ? product.reviews : [];

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const formatCurrency = useCallback((value: number) => {
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency }).format(value);
    } catch {
      return `${currency} ${value.toFixed(2)}`;
    }
  }, [currency]);

  const getSpecificationRows = useCallback(() => {
    return specifications.map((spec, index) => {
      const record = spec as Record<string, unknown>;
      const key = String(record.key ?? record.name ?? record.label ?? `Item ${index + 1}`);
      const value = String(record.value ?? record.detail ?? record.description ?? '');
      return { key, value };
    });
  }, [specifications]);

  const getReviewRows = useCallback(() => {
    return reviews.map((review, index) => {
      const record = review as Record<string, unknown>;
      const author = String(record.author ?? record.name ?? 'Anonymous');
      const text = String(record.text ?? record.comment ?? record.message ?? '');
      const dateValue = record.date ?? record.timestamp ?? '';
      const date = dateValue instanceof Date ? dateValue.toLocaleDateString() : String(dateValue);
      const reviewRating = Math.max(0, Math.min(5, Math.round(Number(record.rating ?? 0))));
      return { id: `${author}-${index}`, author, rating: reviewRating, text, date };
    });
  }, [reviews]);

  const clampQuantity = useCallback((value: number) => {
    if (stock <= 0) return 1;
    return Math.min(stock, Math.max(1, Math.floor(value)));
  }, [stock]);

  const incrementQuantity = useCallback(() => {
    setQuantity((current) => clampQuantity(current + 1));
  }, [clampQuantity]);

  const decrementQuantity = useCallback(() => {
    setQuantity((current) => clampQuantity(current - 1));
  }, [clampQuantity]);

  const handleQuantityChange = useCallback((value: string) => {
    setQuantity(clampQuantity(Number(value) || 1));
  }, [clampQuantity]);

  const handleTabChange = useCallback((key: string) => {
    setActiveTab(key);
  }, []);

  const handleAddToCart = useCallback(() => {
    if (!productId || stock <= 0) return;
    addToCart({ productId, quantity: clampQuantity(quantity) });
    if (typeof props.onAddToCart === 'function') {
      props.onAddToCart({ productId, quantity: clampQuantity(quantity) });
    }
  }, [addToCart, clampQuantity, productId, quantity, stock, props]);

  useRef(productId);

  return {
    addToCart,
    productId,
    productName,
    price,
    currency,
    rating,
    reviewCount,
    stock,
    description,
    specifications,
    reviews,
    quantity,
    activeTab,
    formatCurrency,
    getSpecificationRows,
    getReviewRows,
    incrementQuantity,
    decrementQuantity,
    handleQuantityChange,
    handleTabChange,
    handleAddToCart,
  };
}
}


