      setTypingSender(latest.sender);
      return;
    }
    if (!latest || !latest.active) {
      setTypingSender('');
    }
  }, [props.currentUser, typing.latest]);

  React.useEffect(() => {
    const source = (globalThis as typeof globalThis & { __gguiChatStream?: { message?: StreamMessage | null; typing?: StreamTyping | null } }).__gguiChatStream;
    if (source?.message && source.message.text) {
      const key = makeKey(source.message);
      if (!seenMessageKeysRef.current.has(key)) {
        appendMessage({ sender: source.message.sender, text: source.message.text, timestamp: source.message.timestamp, fromCurrentUser: (source.message.sender || '') === props.currentUser });
      }
    }
    if (source?.typing) {
      if (source.typing.active && source.typing.sender && source.typing.sender !== props.currentUser) {
        setTypingSender(source.typing.sender);
      } else {
        setTypingSender('');
      }
    }
