  const groupedMessages = localMessages.reduce<Array<{ sender: string; fromCurrentUser: boolean; messages: Array<{ sender: string; text: string; timestamp: string; fromCurrentUser?: boolean }> }>>((groups, msg) => {
    const last = groups[groups.length - 1];
    if (last && last.sender === msg.sender && last.fromCurrentUser === Boolean(msg.fromCurrentUser)) {
      last.messages.push(msg);
    } else {
      groups.push({ sender: msg.sender, fromCurrentUser: Boolean(msg.fromCurrentUser), messages: [msg] });
    }
    return groups;
  }, []);

  return { sendMessage, message, typing, draft, setDraft, handleSend, handleSubmit, listRef, groupedMessages, typingSender };
