import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [marketOpen, setMarketOpen] = useState<'open' | 'closed' | 'pre-market' | 'after-hours' | null>(null);
  const [flashSymbols, setFlashSymbols] = useState<Record<string, boolean>>({});
  const flashTimeoutRef = useRef<number | null>(null);

  const toStockKey = useCallback((stock: { symbol?: string; name?: string }) => {
    return (stock.symbol || stock.name || '').trim().toLowerCase();
  }, []);

  const updateStocksFromPayload = useCallback((incoming: Array<Partial<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>) => {
    if (!incoming.length) {
      return;
    }

    setStocks((current) => {
      const next = [...current];
      const flashMap: Record<string, boolean> = {};

      incoming.forEach((item) => {
        const symbol = typeof item.symbol === 'string' ? item.symbol.trim() : '';
        const name = typeof item.name === 'string' ? item.name : undefined;
        const key = symbol || name || '';
        if (!key) {
          return;
        }

        const existingIndex = next.findIndex((stock) => {
          if (symbol && stock.symbol === symbol) {
            return true;
          }
          if (name && stock.name === name) {
            return true;
          }
          return toStockKey(stock) === key.toLowerCase();
        });

        const updated = {
          ...(existingIndex >= 0 ? next[existingIndex] : {}),
          ...(symbol ? { symbol } : {}),
          ...(name ? { name } : {}),
          ...(typeof item.price === 'number' ? { price: item.price } : {}),
          ...(typeof item.change === 'number' ? { change: item.change } : {}),
          ...(typeof item.changePercent === 'number' ? { changePercent: item.changePercent } : {}),
        };

        const resolvedSymbol = updated.symbol || symbol || name || '';
        if (existingIndex >= 0) {
          next[existingIndex] = updated as (typeof current)[number];
        } else {
          next.push(updated as (typeof current)[number]);
        }

        if (resolvedSymbol) {
          flashMap[resolvedSymbol] = true;
        }
      });

      if (Object.keys(flashMap).length > 0) {
        setFlashSymbols((current) => ({ ...current, ...flashMap }));
      }

      return next;
    });
  }, [toStockKey]);

  const handlePriceUpdate = useCallback((update: StreamPriceUpdate | StreamPriceUpdate[] | null | undefined) => {
    if (!update) {
      return;
    }

    const updates = Array.isArray(update) ? update : [update];
    updateStocksFromPayload(updates);
    setLastUpdated(new Date().toLocaleTimeString());
  }, [updateStocksFromPayload]);

  const handleMarketStatus = useCallback((statusEvent: StreamMarketStatus | null | undefined) => {
    if (!statusEvent?.status) {
      return;
    }

    setMarketOpen(statusEvent.status);
    if (statusEvent.timestamp) {
      setLastUpdated(new Date(statusEvent.timestamp).toLocaleTimeString());
    } else {
      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, []);

  React.useEffect(() => {
    setStocks(props.stocks);
  }, [props.stocks]);

  React.useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ type?: string; payload?: StreamPriceUpdate | StreamPriceUpdate[] | StreamMarketStatus | { stocks?: Array<Partial<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>; symbol?: string; price?: number; change?: number; changePercent?: number }; updates?: Array<Partial<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>> }>;
      const detail = customEvent.detail;
      const payload = detail?.payload;
      if (detail?.type === 'priceUpdate') {
        if (Array.isArray(payload)) {
          handlePriceUpdate(payload);
        } else if (payload && typeof payload === 'object' && 'stocks' in payload && Array.isArray(payload.stocks)) {
          updateStocksFromPayload(payload.stocks);
          setLastUpdated(new Date().toLocaleTimeString());
        } else if (payload && typeof payload === 'object' && 'updates' in payload && Array.isArray(payload.updates)) {
          updateStocksFromPayload(payload.updates);
          setLastUpdated(new Date().toLocaleTimeString());
        } else {
          handlePriceUpdate(payload as StreamPriceUpdate | null | undefined);
        }
      }
      if (detail?.type === 'marketStatus') {
        handleMarketStatus(payload as StreamMarketStatus | null | undefined);
      }
    };

    if (typeof window === 'undefined') {
      return undefined;
    }

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, [handleMarketStatus, handlePriceUpdate, updateStocksFromPayload]);

  React.useEffect(() => {
    const timer = window.setTimeout(() => {
      handlePriceUpdate(null);
      handleMarketStatus(null);
    }, 0);

    return () => window.clearTimeout(timer);
  }, [handleMarketStatus, handlePriceUpdate]);

  React.useEffect(() => {
    const timer = window.setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);

    return () => window.clearInterval(timer);
  }, []);

  React.useEffect(() => {
    if (flashTimeoutRef.current !== null) {
      window.clearTimeout(flashTimeoutRef.current);
    }
    const activeSymbols = Object.keys(flashSymbols);
    if (activeSymbols.length === 0) {
      return;
    }

    flashTimeoutRef.current = window.setTimeout(() => {
      setFlashSymbols({});
      flashTimeoutRef.current = null;
    }, 700);

    return () => {
      if (flashTimeoutRef.current !== null) {
        window.clearTimeout(flashTimeoutRef.current);
        flashTimeoutRef.current = null;
      }
    };
  }, [flashSymbols]);

  const positiveCount = stocks.filter((stock) => (stock.change ?? 0) >= 0).length;
  const negativeCount = stocks.filter((stock) => (stock.change ?? 0) < 0).length;

  const marketLabel = marketOpen ? marketOpen.replace('-', ' ') : 'live';

  return {
    stocks,
    lastUpdated,
    marketOpen,
    marketLabel,
    positiveCount,
    negativeCount,
    flashSymbols,
  };
}
}


